const WATCHLISTS_PATH = resolve(dirname(fileURLToPath(import.meta.url)), '..', 'config', 'watchlists.json');

const DEFAULT_SYMBOLS = ['SPY', 'QQQ', 'IWM', 'DIA', 'TLT', 'HYG', 'GLD', 'USO'];

export async function pull(flags = {}) {
